// TypeScript MCP SDK — defining a "read_file" tool
server.tool(
  "read_file",
  "Read the contents of a file at the given path",
  {
    path: z.string().describe("Absolute path to the file"),
  },
  async ({ path }) => ({
    content: [{ type: "text", text: await fs.readFile(path, "utf8") }],
  }),
);

server.prompt(
  "summarise_pr",
  "Summarise a GitHub PR with risks and ask reviewers what to focus on",
  {
    owner: z.string(),
    repo: z.string(),
    number: z.number(),
  },
  async ({ owner, repo, number }) => ({
    messages: [
      {
        role: "user",
        content: {
          type: "text",
          text: `Summarise ${owner}/${repo}#${number}. Highlight risk hotspots.`,
        },
      },
    ],
  }),
);

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

const server = new McpServer({
  name: "hello-mcp",
  version: "1.0.0",
});

server.tool(
  "greet",
  "Greet someone warmly",
  { name: z.string() },
  async ({ name }) => ({
    content: [{ type: "text", text: `Hello, ${name}!` }],
  }),
);

await server.connect(new StdioServerTransport());

server.resource(
  "config",
  "config://app",
  { mimeType: "application/json" },
  async () => ({
    contents: [
      {
        uri: "config://app",
        mimeType: "application/json",
        text: JSON.stringify({ theme: "dark", region: "in-south-1" }),
      },
    ],
  }),
);

server.prompt(
  "review_my_code",
  "Review code with a focus on production-readiness",
  { language: z.string(), code: z.string() },
  async ({ language, code }) => ({
    messages: [
      {
        role: "user",
        content: {
          type: "text",
          text: `Review this ${language} for prod-readiness:\n\n${code}`,
        },
      },
    ],
  }),
);
